 76→/// High-level category for an invariant property description.
 77→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 78→#[serde(rename_all = "snake_case")]
 79→pub enum InvariantCategory {
 80→    NumericBound,
 81→    Nullability,
 82→    StringConstraint,
 83→    ReturnTypeInvariant,
 84→    ErrorInvariant,
 85→    InputOutputRelation,
 86→    BooleanConstant,
 87→    ConstantValue,
 88→}
 89→
 90→/// Categorical confidence derived from the numeric confidence score.
 91→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 92→#[serde(rename_all = "snake_case")]
 93→pub enum ConfidenceLevel {
 94→    High,
 95→    Medium,
 96→    Low,
 97→}
 98→
 99→const CONFIDENCE_HIGH_THRESHOLD: f64 = 0.95;
100→const CONFIDENCE_MEDIUM_THRESHOLD: f64 = 0.75;
101→
102→impl ConfidenceLevel {
103→    fn from_score(score: f64) -> Self {
104→        if score >= CONFIDENCE_HIGH_THRESHOLD {
105→            Self::High
106→        } else if score >= CONFIDENCE_MEDIUM_THRESHOLD {
107→            Self::Medium
108→        } else {
109→            Self::Low
110→        }
111→    }
112→}
