27→/// Iteration count bucket boundaries for scope-aware path hashing.
28→///
29→/// Each threshold defines the upper bound of a bucket. Counts above
30→/// the last threshold all land in the final bucket.
31→/// Default: `[0, 1, 2, 5]` → buckets: 0, 1, 2, 3–5, 6+
32→#[derive(Debug, Clone)]
33→pub struct LoopBuckets(Vec<u32>);
34→
35→impl LoopBuckets {
36→    /// Construct from sorted, deduplicated boundary values.
37→    /// Panics if boundaries are not sorted or contain duplicates.
38→    pub fn from_boundaries(mut boundaries: Vec<u32>) -> Self {
39→        boundaries.sort_unstable();
40→        boundaries.dedup();
41→        Self(boundaries)
42→    }
43→
44→    /// Disable bucketing entirely — iteration counts are ignored (current behavior).
45→    pub fn none() -> Self {
46→        Self(Vec::new())
47→    }
48→
49→    /// Returns `true` when bucketing is disabled.
50→    pub fn is_disabled(&self) -> bool {
51→        self.0.is_empty()
52→    }
53→
54→    /// Map an iteration count to a bucket index (0-based).
55→    /// Bucket *i* covers counts in `(boundaries[i-1], boundaries[i]]`
56→    /// (with bucket 0 covering `[0, boundaries[0]]`).
57→    /// Counts above the last boundary land in the final bucket.
58→    pub fn bucket(&self, count: u32) -> u32 {
59→        for (i, &threshold) in self.0.iter().enumerate() {
60→            if count <= threshold {
61→                return i as u32;
62→            }
63→        }
64→        self.0.len() as u32
65→    }
66→}
67→
68→impl Default for LoopBuckets {
69→    fn default() -> Self {
70→        Self(vec![0, 1, 2, 5])
71→    }
72→}
