  1→//!
  2→//! A fingerprint is a stable SHA-256 hash of a function's source text,
  3→//! parameter types, and branch structure. When a fingerprint matches a
  4→//! previously cached value, the function is unchanged and can be skipped
  5→//! during re-exploration.
  6→
  7→use std::collections::{HashMap, HashSet};
  8→use std::fmt::Write as _;
  9→use std::path::Path;
 10→
 11→use sha2::{Digest, Sha256};
 12→
 13→use crate::protocol::FunctionAnalysis;
 14→
 15→/// Compute a hex-encoded SHA-256 fingerprint for a function.
 16→///
 17→/// The fingerprint incorporates:
 18→/// - The function's source text (verbatim, including whitespace)
 19→/// - Parameter names and types (sorted by name for stability)
 20→/// - Branch structure: IDs, lines, condition text, types (sorted by ID)
 21→///
 22→/// Any change to these inputs produces a different fingerprint.
 23→pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
 24→    let mut hasher = Sha256::new();
 25→
 26→    // Hash source text.
 27→    hasher.update(b"source:");
 28→    hasher.update(source_text.as_bytes());
 29→
 30→    // Hash parameters (sorted by name for determinism).
 31→    let mut params: Vec<_> = analysis
 32→        .params
 33→        .iter()
 34→        .map(|p| {
 35→            let mut s = String::new();
 36→            let _ = write!(s, "{}:{:?}", p.name, p.typ);
 37→            if let Some(ref tn) = p.type_name {
 38→                let _ = write!(s, "/{tn}");
 39→            }
 40→            s
 41→        })
 42→        .collect();
 43→    params.sort();
 44→
 45→    hasher.update(b"params:");
 46→    for p in &params {
 47→        hasher.update(p.as_bytes());
 48→        hasher.update(b"\n");
 49→    }
 50→
 51→    // Hash branch structure (sorted by branch ID for determinism).
 52→    let mut branches: Vec<_> = analysis
 53→        .branches
 54→        .iter()
 55→        .map(|b| {
 56→            let mut s = String::new();
 57→            let _ = write!(s, "{}:{}:{:?}:{}", b.id, b.line, b.branch_type, b.condition_text);
 58→            s
 59→        })
 60→        .collect();
 61→    branches.sort();
 62→
 63→    hasher.update(b"branches:");
 64→    for b in &branches {
 65→        hasher.update(b.as_bytes());
 66→        hasher.update(b"\n");
 67→    }
 68→
 69→    format!("{:x}", hasher.finalize())
 70→}
