1023→/// Explore a single function and build its result.
1024→///
1025→/// This is the core work unit for both sequential and parallel scanning.
1026→#[allow(clippy::too_many_arguments)]
1027→async fn explore_single_function(
1028→    frontend: &mut Frontend,
1029→    func_name: &str,
1030→    analysis: &FunctionAnalysis,
1031→    explore_config: &ExploreConfig,
1032→    mocks_used: &[MockUsage],
1033→    callees: &std::collections::HashSet<String>,
1034→    behavior_maps: &Mutex<HashMap<String, BehaviorMap>>,
1035→    fingerprint: Option<String>,
1036→    input_pool: &Mutex<InterestingPool>,
1037→) -> Result<FunctionResult, ScanError> {
1038→    let exploration = explorer::explore_function(frontend, analysis, explore_config).await?;
1039→
1040→    // Harvest interesting inputs into the cross-function pool.
1041→    {
1042→        let mut pool_guard = input_pool.lock().await;
1043→        interesting_pool::harvest_from_exploration(
1044→            &mut pool_guard,
1045→            &exploration.raw_results,
1046→            &analysis.params,
1047→            func_name,
1048→        );
1049→    }
1050→
1051→    // Run the Analyze stage to produce behavior map and coverage metrics.
1052→    let mut analyze_out = crate::pipeline::analyze(&exploration, analysis);
1053→    analyze_out.behavior_map.fingerprint = fingerprint;
1054→
1055→    // Compute behavior coverage for each callee (cross-function concern).
1056→    let records: Vec<ExecutionRecord> = exploration
1057→        .raw_results
1058→        .iter()
1059→        .map(|(inputs, result)| execution_record_from_result(func_name, inputs, result))
1060→        .collect();
1061→    let maps = behavior_maps.lock().await;
1062→    let mut behavior_coverage: Vec<BehaviorCoverage> = Vec::new();
1063→    for callee in callees {
1064→        if let Some(callee_map) = maps.get(callee) {
1065→            let coverage = BehaviorCoverage::compute(func_name, &records, callee_map);
1066→            behavior_coverage.push(coverage);
1067→        }
1068→    }
1069→    drop(maps);
1070→
1071→    Ok(FunctionResult {
1072→        function_name: func_name.to_string(),
1073→        exploration,
1074→        behavior_map: analyze_out.behavior_map,
1075→        behavior_coverage,
1076→        mocks_used: mocks_used.to_vec(),
1077→        coverage_metrics: analyze_out.coverage_metrics,
1078→    })
1079→}
