1081→/// Format mock usages as a human-readable string with source attribution.
1082→fn format_mocks_used(mocks: &[MockUsage]) -> String {
1083→    let cached: Vec<&str> = mocks
1084→        .iter()
1085→        .filter(|m| m.source == MockSource::CachedBehaviorMap)
1086→        .map(|m| m.name.as_str())
1087→        .collect();
1088→    let stubs: Vec<&str> = mocks
1089→        .iter()
1090→        .filter(|m| m.source == MockSource::TypeAwareStub)
1091→        .map(|m| m.name.as_str())
1092→        .collect();
1093→
1094→    let mut parts = Vec::new();
1095→    if !cached.is_empty() {
1096→        parts.push(format!("{} via behavior map ({})", cached.len(), cached.join(", ")));
1097→    }
1098→    if !stubs.is_empty() {
1099→        parts.push(format!("{} via type-aware stub ({})", stubs.len(), stubs.join(", ")));
1100→    }
1101→    parts.join("; ")
1102→}
