  1→//! Disk cache for [`BehaviorMap`]s, enabling persistence across runs.
  2→//!
  3→//! When shatter explores a function, the resulting behavior map is stored to disk
  4→//! so it can be reloaded in future runs — critical for compositional testing where
  5→//! function B's behavior map is reused when testing function A.
  6→
  7→use std::fs;
  8→use std::path::{Path, PathBuf};
  9→
 10→use crate::behavior::BehaviorMap;
 11→
 12→/// Errors that can occur during cache operations.
 13→#[derive(Debug, thiserror::Error)]
 14→pub enum CacheError {
 15→    #[error("cache I/O error: {0}")]
 16→    Io(#[from] std::io::Error),
 17→    #[error("cache serialization error: {0}")]
 18→    Serialization(#[from] serde_json::Error),
 19→}
 20→
 21→/// Disk-backed cache for storing and loading [`BehaviorMap`]s.
 22→#[derive(Debug)]
 23→pub struct BehaviorMapCache {
 24→    cache_dir: PathBuf,
 25→}
 26→
 27→impl BehaviorMapCache {
 28→    /// Create a new cache backed by the given directory.
 29→    ///
 30→    /// Creates the directory (and parents) if it doesn't exist.
 31→    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
 32→        fs::create_dir_all(&cache_dir)?;
 33→        Ok(Self { cache_dir })
 34→    }
 35→
 36→    /// Load a behavior map for the given function ID, if one exists.
 37→    ///
 38→    /// Returns `Ok(None)` if no cached map exists for this function.
 39→    pub fn load(&self, function_id: &str) -> Result<Option<BehaviorMap>, CacheError> {
 40→        let path = self.path_for(function_id);
 41→        match fs::read_to_string(&path) {
 42→            Ok(contents) => {
 43→                let map: BehaviorMap = serde_json::from_str(&contents)?;
 44→                Ok(Some(map))
 45→            }
 46→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
 47→            Err(e) => Err(CacheError::Io(e)),
 48→        }
 49→    }
 50→
 51→    /// Store a behavior map to disk using atomic write (temp file + rename).
 52→    pub fn store(&self, map: &BehaviorMap) -> Result<(), CacheError> {
 53→        let path = self.path_for(&map.function_id);
 54→        let json = serde_json::to_string_pretty(map)?;
 55→
 56→        // Ensure parent directories exist for hierarchical cache paths.
 57→        if let Some(parent) = path.parent() {
 58→            fs::create_dir_all(parent)?;
 59→        }
 60→
 61→        // Atomic write: write to a temp file in the same directory, then rename.
 62→        let tmp_path = path.with_extension("json.tmp");
 63→        fs::write(&tmp_path, json)?;
 64→        fs::rename(&tmp_path, &path)?;
 65→
 66→        Ok(())
 67→    }
 68→
 69→    /// Check whether a cached behavior map exists and its fingerprint matches.
 70→    ///
 71→    /// Returns `true` if the cache contains a map for `function_id` whose
 72→    /// fingerprint equals `current_fingerprint`. Returns `false` if no cached
 73→    /// map exists, the cached map has no fingerprint, or the fingerprints differ.
 74→    pub fn is_fresh(
 75→        &self,
 76→        function_id: &str,
 77→        current_fingerprint: &str,
 78→    ) -> Result<bool, CacheError> {
 79→        match self.load(function_id)? {
 80→            Some(map) => Ok(map
 81→                .fingerprint
 82→                .as_deref()
 83→                .is_some_and(|fp| fp == current_fingerprint)),
 84→            None => Ok(false),
 85→        }
 86→    }
 87→
 88→    /// Default cache directory relative to a project root: `<project_root>/.shatter/cache/`.
 89→    pub fn default_dir(project_root: &Path) -> PathBuf {
 90→        project_root.join(".shatter").join("cache")
 91→    }
 92→
 93→    /// Compute the file path for a given function ID.
 94→    ///
 95→    /// Mirrors the source tree structure:
 96→    /// - `src/auth.ts:validateToken` → `src/auth.ts/validateToken.json`
 97→    /// - `src/auth.ts:TokenValidator.validate` → `src/auth.ts/TokenValidator/validate.json`
 98→    /// - `simpleFunc` (no colon) → `simpleFunc.json`
 99→    fn path_for(&self, function_id: &str) -> PathBuf {
100→        let mut path = self.cache_dir.clone();
101→
102→        let (file_part, func_part) = match function_id.split_once(':') {
103→            Some((f, func)) => (Some(f), func),
104→            None => (None, function_id),
105→        };
106→
107→        // Append file path components (each sanitized individually).
108→        if let Some(file) = file_part {
109→            for component in file.split('/') {
110→                if !component.is_empty() {
111→                    path.push(sanitize_component(component));
112→                }
113→            }
114→        }
115→
116→        // Split func_part on '.' for class.method.
117→        match func_part.split_once('.') {
118→            Some((class_name, method_name)) => {
119→                path.push(sanitize_component(class_name));
120→                path.push(format!("{}.json", sanitize_component(method_name)));
121→            }
122→            None => {
123→                path.push(format!("{}.json", sanitize_component(func_part)));
124→            }
125→        }
126→
127→        path
128→    }
129→}
130→
131→/// Sanitize a single path component for safe use as a filename.
132→///
133→/// Replaces unsafe characters with underscores to prevent path traversal attacks.
134→/// Called per-component after splitting on `/` and `:`, so those delimiters
135→/// are not expected in the input.
136→fn sanitize_component(component: &str) -> String {
137→    component
138→        .chars()
139→        .enumerate()
140→        .map(|(i, c)| match c {
141→            '\\' | '*' | '?' | '"' | '<' | '>' | '|' | '\0' => '_',
142→            '.' if i == 0 => '_', // prevent hidden files for leading dots
143→            _ => c,
144→        })
145→        .collect()
146→}
147→
